import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, tfm, pkg = key
    bv = b.get(key, 'N/A')
    av = a.get(key, 'N/A')
    if bv != av:
        changes.append((proj, tfm, pkg, bv, av))
    else:
        unchanged.append((proj, tfm, pkg, av))

print('=== CHANGES ===')
if changes:
    print(f'{'Project':<16} {'TFM':<8} {'Package':<45} {'Before':<10} {'After':<10}')
    for p,t,pkg,bv,av in changes:
        print(f'{p:<16} {t:<8} {pkg:<45} {bv:<10} {av:<10}')
else:
    print('No version changes detected.')

print()
print('=== UNCHANGED ===')
print(f'{'Project':<16} {'TFM':<8} {'Package':<45} {'Version':<10}')
for p,t,pkg,v in unchanged:
    print(f'{p:<16} {t:<8} {pkg:<45} {v:<10}')
"
